def find_last_occurrence(arr, target):
    """
    arr: 정렬된 배열
    target: 찾을 숫자
    """

    # 이진 탐색을 위한 함수
    def binary_search(left, right):
        # 중간 인덱스
        mid = (left + right) // 2

        # 중간 인덱스의 값이 찾고자 하는 값과 같다면
        if arr[mid] == target:
            # 중간 인덱스가 마지막 인덱스라면
            if mid == len(arr) - 1:
                return mid
            # 중간 인덱스의 오른쪽 인덱스부터 다시 탐색
            else:
                return binary_search(mid + 1, right)
        # 중간 인덱스의 값이 찾고자 하는 값보다 작다면
        elif arr[mid] < target:
            # 왼쪽 인덱스부터 다시 탐색
            return binary_search(left, mid - 1)
        # 중간 인덱스의 값이 찾고자 하는 값보다 크다면
        else:
            # 오른쪽 인덱스부터 다시 탐색
            return binary_search(mid + 1, right)

    # 배열의 마지막 인덱스부터 시작하여 찾고자 하는 값의 마지막 인덱스를 찾음
    return binary_search(0, len(arr) - 1)

