    # 딕셔너리에서 각 키의 개수를 추출하여 새로운 딕셔너리에 저장
    unique_count = {}
    for key, value in dic.items():
        unique_count[key] = value

    # 딕셔너리에서 키의 개수를 추출하여 새로운 딕셔너리에 저장
    unique_keys = {}
    for key, value in unique_count.items():
