        if not 1 <= day <= 30:
            return False
    elif month == 2:
        if not (1 <= day <= 29 or (year % 4 == 0 and year % 100 != 0 and day == 29)):
            return False
    else:
        if not 1 <= day <= 31:
            return False

    # 년도는 1에서 9999 사이인지 확인합니다.
    if not 1 <= year <= 9999:
        return False

    # 위의 조건을 모두 만족하면 날짜가 유효한 날짜입니다.
    return True
