def check_k_elements(tuple_list, k):
    # 주어진 튜플 리스트가 비어 있지 않은지 확인합니다.
    if not tuple_list:
        return False

    # 주어진 튜플 리스트의 길이가 k와 일치하는지 확인합니다.
    if len(tuple_list) != k:
        return False

    # 주어진 튜플 리스트의 모든 원소가 튜플인지 확인합니다.
    if not all(isinstance(x, tuple) for x in tuple_list):
        return False

    # 주어진 튜플 리스트의 모든 튜플의 길이가 일치하는지 확인합니다.
    tuple_length = len(tuple_list[0])
    if not all(len(x) == tuple_length for x in tuple_list):
        return False

    # 주어진 튜플 리스트의 모든 원소가 k 길이의 튜플인지 확인합니다.
    return all(len(x) == k for x in tuple_list)
