def char_frequency(s):
    # 문자열을 소문자로 변환하여 빈도수를 계산하기 위해
    s = s.lower()

    # 빈도수를 저장할 딕셔너리 생성
    freq = {}

    # 각 문자의 빈도수를 계산
    for char in s:
        # 문자가 이미 딕셔너리에 있으면 빈도수 1 증가
        if char in freq:
            freq[char] += 1
        # 문자가 딕셔너리에 없으면 새로 추가하고 빈도수 1
        else:
            freq[char] = 1

    # 빈도수를 정렬하여 반환
    return dict(sorted(freq.items(), key=lambda item: item[1], reverse=True))

# 테스트
print(char_frequency("Hello, World!"))
```

