def solve(arr):
    # 두 배열의 길이가 다르면 비교할 수 없음
    if len(arr) != len(arr[0]):
        return False

    # 첫 번째 배열에서 각 원소의 개수를 세어 dictionary에 저장
    count1 = {}
    for num in arr[0]:
        if num in count1:
            count1[num] += 1
        else:
            count1[num] = 1

    # 두 번째 배열에서 각 원소의 개수를 세어 dictionary에 저장
    count2 = {}
    for num in arr[1]:
        if num in count2:
            count2[num] += 1
        else:
            count2[num] = 1

    # 두 dictionary의 key-value pair를 비교하여 inversion count가 같은지 확인
    for key in count1:
        if key not in count2 or count1[key] != count2[key]:
            return False

    return True
```

