def convert_list_dictionary(*args):
    """
    여러 개의 리스트를 중첩된 딕셔너리로 변환하는 함수입니다.

    Args:
        *args: 변환할 리스트의 개수와 종류가 자유롭습니다.

    Returns:
        중첩된 딕셔너리
    """

    # 만약 인자가 하나 이상이면, 첫 번째 인자를 키로 두 번째 인자를 값으로 하는 딕셔너리를 생성합니다.
    if len(args) > 1:
        result = {args[0][0]: args[1]}
    else:
        result = {}

    # 만약 인자가 두 개 이상이면, 중첩된 딕셔너리를 생성합니다.
    if len(args) > 2:
        # 인자의 개수만큼 반복합니다.
        for i in range(2, len(args)):
            # 만약 인자가 짝수 개라면, 중첩된 딕셔너리를 생성합니다.
            if i % 2 == 0:
                # 이전 결과를 키로, 현재 인자를 값으로 하는 중첩된 딕셔너리를 생성합니다.
                result = {key: convert_list_dictionary(*args[i-1:i+1]) for key in result}
            # 만약 인자가 홀수 개라면, 중첩된 딕셔너리를 생성합니다.
            else:
                # 이전 결과를 키로, 현재 인자의 첫 번째 요소를 값으로 하는 중첩된 딕셔너리를 생성합니다.
                result = {key: convert_list_dictionary(*args[i-1:i+1])[0] for key in result}

    # 결과를 반환합니다.
    return result

# 예시
list1 = ['a', 'b', 'c']
list2 = [1, 2, 3]
list3 = ['x', 'y', 'z']

result = convert_list_dictionary(list1, list2, list3)
print(result)
```

이 함수는 여러 개의 리스트를 중첩된 딕셔너리로 변환하는 데 사용할 수 있습니다. 예를 들어, `list1`, `list2`, `list3`을 중첩된 딕셔너리로 변환하려면 `convert_list_dictionary(list1, list2, list3)`을 호출하면 됩니다.

