def divisible_by_digits(start, end):
    def is_divisible(num):
        # 각 자릿수에 대해 숫자가 해당 자릿수에 의해 나누어 떨어지는지 확인합니다.
        for digit in str(num):
            # 숫자가 0보다 작거나 같을 때는 0으로 나누는 것은 정의상 불가능하므로 예외 처리합니다.
            if digit == '0' and num % 10 == 0:
                continue
            # 숫자가 0으로 나누어 떨어지지 않으면 False를 반환합니다.
            if num % int(digit) != 0:
                return False
        # 모든 자릿수가 해당 숫자를 나누어 떨어렸으면 True를 반환합니다.
        return True

    # 주어진 범위 내의 모든 숫자를 확인합니다.
    for num in range(start, end + 1):
        # 숫자가 모든 자릿수에 의해 나누어 떨어진다면 True를 반환합니다.
        if is_divisible(num):
            yield num

# 예시 사용
for num in divisible_by_digits(10, 100):
    print(num)
