def tuple_intersection(tuple_list):
    # 주어진 튜플 리스트에서 중복된 원소를 제거하고 집합으로 변환
    set_list = set(tuple_ for tup in tuple_list for tuple_ in tup)

    # 집합의 크기 구하기
    n = len(set_list)

    # 결과를 저장할 집합
    result = set()

    # 각 원소가 몇 개 있는지 카운트
    count = {}
    for tup in tuple_list:
        for elem in tup:
            if elem in count:
                count[elem] += 1
            else:
                count[elem] = 1

    # 원소가 2개 이상인 원소만 결과에 추가
    for elem in set_list:
        if count[elem] >= 2:
            result.add(elem)

    # 결과를 튜플로 변환
    return tuple(result)

