def get_odd_occurence(arr):
    # 주어진 배열에서 각 원소의 개수를 세어 딕셔너리에 저장합니다.
    count_dict = {}
    for num in arr:
        if num in count_dict:
            count_dict[num] += 1
        else:
            count_dict[num] = 1

    # 딕셔너리에서 개수가 홀수인 원소를 찾습니다.
    odd_occurence = [num for num, count in count_dict.items() if count % 2 != 0]

    # 개수가 홀수인 원소가 여러 개일 경우, 가장 작은 원소를 반환합니다.
    return min(odd_occurence) if odd_occurence else None
