def max_path_sum(triangle):
    # 삼각형의 각 행을 반복하여 처리합니다.
    for i in range(len(triangle) - 2, -1, -1):
        # 각 행의 각 원소에 대해, 그 원소와 바로 아래 원소의 합을 계산합니다.
        for j in range(len(triangle[i])):
            # 삼각형의 마지막 행은 더 이상 아래 원소가 없으므로, 그 원소의 값을 그대로 저장합니다.
            if i == len(triangle) - 1:
                triangle[i][j] = triangle[i][j]
            else:
                # 삼각형의 각 원소는, 그 원소와 바로 아래 원소의 합과, 그 원소와 바로 왼쪽 원소의 합 중 더 큰 값을 저장합니다.
                triangle[i][j] = max(triangle[i][j] + triangle[i + 1][j], triangle[i][j] + triangle[i + 1][j + 1])

    # 삼각형의 첫 번째 행에 저장된 원소 중 가장 큰 값을 반환합니다.
    return max(triangle[0])
