def check_expression(expression):
    # 괄호의 종류를 저장할 딕셔너리
    bracket_dict = {'(': ')', '[': ']', '{': '}'}

    # 스택을 초기화
    stack = []

    # 각 문자를 확인
    for char in expression:
        # 여는 괄호인 경우 스택에 추가
        if char in bracket_dict.keys():
            stack.append(char)
        # 닫는 괄호인 경우
        elif char in bracket_dict.values():
            # 스택이 비어있거나, 현재 스택의 top이 현재 닫는 괄호와 일치하지 않는 경우
            if not stack or bracket_dict[stack.pop()] != char:
                return False

    # 스택이 비어있지 않으면, 괄호가 불균형
    if stack:
        return False

    # 괄호가 모두 짝이 맞는 경우
    return True
