def move_num(s):
    # 문자열에서 숫자를 추출하는 함수
    def extract_num(s):
        num = ''
        for char in s:
            if char.isdigit():
                num += char
            elif num:
                yield num
                num = ''
        if num:
            yield num

    # 문자열에서 숫자를 추출한 후 결과를 반환하는 함수
    def move_nums(s):
        return ''.join(num for num in extract_num(s))

    return move_nums(s)

