def highest_Power_of_2(n):
    # n이 0보다 작을 때는 0을 반환합니다.
    if n < 0:
        return 0

    # 2의 제곱을 계산하여 n보다 큰 2의 제곱을 찾습니다.
    power = 1
    while 2 ** power <= n:
        power += 1

    # n보다 작은 2의 제곱을 반환합니다.
    return 2 ** (power - 1)
```

