def count_Fac(n):
    # 소수인지 확인하는 함수
    def is_prime(num):
        if num < 2:
            return False
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                return False
        return True

    # 소인수 분해 함수
    def prime_factorization(num):
        factors = {}
        i = 2
        while num > 1:
            if num % i == 0:
                if i in factors:
                    factors[i] += 1
                else:
                    factors[i] = 1
                num //= i
            else:
                i += 1
        return factors

    # 소인수 분해한 후 각 소수의 지수를 세서 반환
    factors = prime_factorization(n)
    count = 0
    for factor in factors:
        count += factors[factor]
    return count

