import math

def answer(nums, low, high):
    # 모든 숫자를 소인수 분해하여 저장
    factors = {}
    for num in nums:
        for i in range(2, int(math.sqrt(num)) + 1):
            while num % i == 0:
                if i in factors:
                    factors[i] += 1
                else:
                    factors[i] = 1
                num //= i
        if num > 1:
            if num in factors:
                factors[num] += 1
            else:
                factors[num] = 1

    # 두 숫자의 LCM을 찾는 함수
    def lcm(a, b):
        return a * b // math.gcd(a, b)

    # 두 숫자의 LCM이 주어진 범위 내에 있는지 확인
    for i in range(len(nums)):
        for j in range(i + 1, len(nums)):
            if low <= lcm(nums[i], nums[j]) <= high:
                return [nums[i], nums[j]]

    # 두 숫자의 LCM이 주어진 범위 내에 없을 경우 None을 반환
    return None
```

