def is_Two_Alter(s):
    # 문자열이 비어 있는 경우 False를 반환합니다.
    if not s:
        return False

    # 문자열의 길이가 홀수인 경우 False를 반환합니다.
    if len(s) % 2 != 0:
        return False

    # 문자열의 첫 번째 문자와 두 번째 문자가 다르면 False를 반환합니다.
    if s[0] != s[1]:
        return False

    # 문자열의 첫 번째 문자와 두 번째 문자가 같다면, 
    # 나머지 문자열의 모든 문자가 첫 번째 문자와 두 번째 문자의 순서만 반복하는지 확인합니다.
    for i in range(2, len(s), 2):
        if s[i] != s[0]:
            return False
        if s[i+1] != s[1]:
            return False

    # 모든 조건을 통과했다면 True를 반환합니다.
    return True
