def flatten(nested_tuple):
    """
    flatten() 함수는 mixed nested tuple에서 각 원소의 빈도수를 계산하는 함수입니다.

    Args:
        nested_tuple (tuple): mixed nested tuple

    Returns:
        dict: 각 원소의 빈도수
    """
    # flatten() 함수를 호출할 때, nested tuple이 비어 있으면 빈 딕셔너리를 반환합니다.
    if not nested_tuple:
        return {}

    # flatten() 함수를 호출할 때, nested tuple이 원소가 하나만 있으면 그 원소의 빈도수를 반환합니다.
    if isinstance(nested_tuple, tuple) and len(nested_tuple) == 1:
        return {nested_tuple[0]: 1}

    # flatten() 함수를 호출할 때, nested tuple이 원소가 여러 개 있으면 각 원소의 빈도수를 계산합니다.
    else:
        # flatten() 함수를 호출할 때, nested tuple의 원소가 tuple이면 flatten() 함수를 재귀적으로 호출합니다.
        freq_dict = {}
        for item in nested_tuple:
            if isinstance(item, tuple):
                freq_dict.update(flatten(item))
            else:
                freq_dict[item] = freq_dict.get(item, 0) + 1
        return freq_dict

# 예시
nested_tuple = (1, 2, (3, 3), (4, (5, 5)), 6, 6, 6)
print(flatten(nested_tuple))  # {1: 1, 2: 1, 3: 2, 4: 1, 5: 2, 6: 3}
```

이 함수는 재귀적으로 nested tuple의 원소를 처리하여 각 원소의 빈도수를 계산합니다. nested tuple이 비어 있거나 원소가 하나만 있으면 빈 딕셔너리를 반환합니다. nested tuple의 원소가 tuple이면 flatten() 함수를 재귀적으로 호출하여 각 원소의 빈도수를 계산합니다. nested tuple의 원소가 원소가 여러 개 있으면 각 원소의 빈도수를 계산합니다.

